const express = require('express');
const redis = require('redis');
const crypto = require('crypto');
const { promisify } = require('util');

const app = express();
const redisClient = redis.createClient({
  host: process.env.REDIS_HOST || 'localhost',
  port: process.env.REDIS_PORT || 6379,
  password: process.env.REDIS_PASSWORD
});

const getAsync = promisify(redisClient.get).bind(redisClient);
const setexAsync = promisify(redisClient.setex).bind(redisClient);

// Idempotency middleware
async function idempotencyMiddleware(req, res, next) {
  // Only apply to state-changing methods
  if (!['POST', 'PUT', 'PATCH', 'DELETE'].includes(req.method)) {
    return next();
  }

  const idempotencyKey = req.headers['idempotency-key'];

  if (!idempotencyKey) {
    return res.status(400).json({
      error: 'Missing required Idempotency-Key header',
      code: 'IDEMPOTENCY_KEY_REQUIRED'
    });
  }

  // Validate idempotency key format (UUID v4)
  const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
  if (!uuidRegex.test(idempotencyKey)) {
    return res.status(400).json({
      error: 'Invalid Idempotency-Key format. Must be UUID v4',
      code: 'INVALID_IDEMPOTENCY_KEY'
    });
  }

  // Create request fingerprint
  const fingerprint = crypto.createHash('sha256')
    .update(JSON.stringify({
      userId: req.user?.id,
      path: req.path,
      method: req.method,
      body: req.body
    }))
    .digest('hex');

  const redisKey = `idempotency:${idempotencyKey}`;

  try {
    const cached = await getAsync(redisKey);

    if (cached) {
      const cachedData = JSON.parse(cached);

      // Verify request parameters match (detect key reuse with different payload)
      if (cachedData.fingerprint !== fingerprint) {
        return res.status(422).json({
          error: 'Idempotency key reused with different parameters',
          code: 'IDEMPOTENCY_KEY_MISMATCH'
        });
      }

      // Return cached response
      return res.status(cachedData.statusCode).json(cachedData.response);
    }

    // Store original send function
    const originalSend = res.send;
    const originalJson = res.json;

    // Intercept response to cache it
    res.json = function(body) {
      const responseData = {
        fingerprint,
        statusCode: res.statusCode,
        response: body,
        timestamp: new Date().toISOString()
      };

      // Cache for 24 hours (86400 seconds)
      setexAsync(redisKey, 86400, JSON.stringify(responseData))
        .catch(err => console.error('Failed to cache idempotency response:', err));

      return originalJson.call(this, body);
    };

    next();
  } catch (error) {
    console.error('Idempotency check failed:', error);
    return res.status(500).json({
      error: 'Internal server error during idempotency check',
      code: 'IDEMPOTENCY_CHECK_FAILED'
    });
  }
}

// Apply middleware globally
app.use(express.json());
app.use(idempotencyMiddleware);

// Payment endpoint example
app.post('/api/v1/payments', async (req, res) => {
  const { amount, currency, paymentMethodId } = req.body;

  // Validate payment parameters
  if (!amount || !currency || !paymentMethodId) {
    return res.status(400).json({ error: 'Missing required payment parameters' });
  }

  try {
    // Process payment (this will only execute once per idempotency key)
    const payment = await processPayment({
      userId: req.user.id,
      amount,
      currency,
      paymentMethodId,
      idempotencyKey: req.headers['idempotency-key']
    });

    res.status(201).json({
      success: true,
      paymentId: payment.id,
      amount: payment.amount,
      status: payment.status
    });
  } catch (error) {
    console.error('Payment processing failed:', error);
    res.status(500).json({ error: 'Payment processing failed' });
  }
});

app.listen(3000, () => console.log('Server running on port 3000'));

const { Pool } = require('pg');
const crypto = require('crypto');

const pool = new Pool({
  host: process.env.DB_HOST,
  database: process.env.DB_NAME,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000
});

// Create idempotency table
const createTableSQL = `
CREATE TABLE IF NOT EXISTS idempotency_keys (
  idempotency_key UUID PRIMARY KEY,
  user_id VARCHAR(255) NOT NULL,
  request_path VARCHAR(500) NOT NULL,
  request_fingerprint VARCHAR(64) NOT NULL,
  response_status INT,
  response_body JSONB,
  created_at TIMESTAMP DEFAULT NOW(),
  expires_at TIMESTAMP DEFAULT NOW() + INTERVAL '24 hours'
);

CREATE INDEX IF NOT EXISTS idx_idempotency_expires ON idempotency_keys(expires_at);
CREATE INDEX IF NOT EXISTS idx_idempotency_user ON idempotency_keys(user_id);
`;

async function processIdempotentRequest(idempotencyKey, userId, requestPath, requestBody, handler) {
  const client = await pool.connect();

  try {
    await client.query('BEGIN');

    // Generate request fingerprint
    const fingerprint = crypto.createHash('sha256')
      .update(JSON.stringify({ userId, requestPath, body: requestBody }))
      .digest('hex');

    // Acquire advisory lock based on idempotency key hash
    const lockId = parseInt(crypto.createHash('sha256')
      .update(idempotencyKey)
      .digest('hex')
      .substring(0, 15), 16) % 2147483647; // Max int value

    await client.query('SELECT pg_advisory_xact_lock($1)', [lockId]);

    // Check if request already processed
    const existingResult = await client.query(
      `SELECT response_status, response_body, request_fingerprint 
       FROM idempotency_keys 
       WHERE idempotency_key = $1 AND expires_at > NOW()`,
      [idempotencyKey]
    );

    if (existingResult.rows.length > 0) {
      const existing = existingResult.rows[0];

      // Verify fingerprint matches
      if (existing.request_fingerprint !== fingerprint) {
        await client.query('ROLLBACK');
        return {
          status: 422,
          body: {
            error: 'Idempotency key reused with different parameters',
            code: 'IDEMPOTENCY_KEY_MISMATCH'
          }
        };
      }

      await client.query('COMMIT');
      return {
        status: existing.response_status,
        body: existing.response_body,
        cached: true
      };
    }

    // Process the request
    const result = await handler(client, requestBody);

    // Store idempotency record
    await client.query(
      `INSERT INTO idempotency_keys 
       (idempotency_key, user_id, request_path, request_fingerprint, response_status, response_body)
       VALUES ($1, $2, $3, $4, $5, $6)`,
      [idempotencyKey, userId, requestPath, fingerprint, result.status, result.body]
    );

    await client.query('COMMIT');
    return result;

  } catch (error) {
    await client.query('ROLLBACK');
    throw error;
  } finally {
    client.release();
  }
}

