// Cleanup expired idempotency keys (run periodically)
async function cleanupExpiredKeys() {
  const result = await pool.query(
    'DELETE FROM idempotency_keys WHERE expires_at < NOW()'
  );
  console.log(`Cleaned up ${result.rowCount} expired idempotency keys`);
}

// Run cleanup every hour
setInterval(cleanupExpiredKeys, 60 * 60 * 1000);

module.exports = { processIdempotentRequest, processPayment };

const stripe = require('stripe')(process.env.STRIPE_SECRET_KEY);
const { v4: uuidv4 } = require('uuid');

/**
 * Client-side: Generate and attach idempotency key to payment requests
 */
class PaymentClient {
  constructor(apiKey) {
    this.apiKey = apiKey;
    this.baseURL = 'https://api.yourcompany.com';
  }

  async createPayment(paymentData, options = {}) {
    // Generate unique idempotency key if not provided
    const idempotencyKey = options.idempotencyKey || uuidv4();

    // Store idempotency key locally to enable safe retries
    const requestId = this.storeRequestMetadata({
      idempotencyKey,
      endpoint: '/api/v1/payments',
      payload: paymentData,
      timestamp: Date.now()
    });

    try {
      const response = await fetch(`${this.baseURL}/api/v1/payments`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${this.apiKey}`,
          'Idempotency-Key': idempotencyKey,
          'X-Request-ID': requestId
        },
        body: JSON.stringify(paymentData)
      });

      if (!response.ok) {
        throw new Error(`Payment failed: ${response.status}`);
      }

      const result = await response.json();
      this.clearRequestMetadata(requestId);
      return result;

    } catch (error) {
      // Automatically retry with same idempotency key on network errors
      if (this.isRetryableError(error) && options.retries > 0) {
        console.log(`Retrying payment with same idempotency key: ${idempotencyKey}`);
        return this.createPayment(paymentData, {
          ...options,
          idempotencyKey, // Reuse same key!
          retries: options.retries - 1
        });
      }
      throw error;
    }
  }

  isRetryableError(error) {
    return error.code === 'ECONNRESET' ||
           error.code === 'ETIMEDOUT' ||
           error.message.includes('network');
  }

  storeRequestMetadata(metadata) {
    // Store in localStorage, IndexedDB, or Redis for distributed systems
    const requestId = uuidv4();
    localStorage.setItem(`request:${requestId}`, JSON.stringify(metadata));
    return requestId;
  }

  clearRequestMetadata(requestId) {
    localStorage.removeItem(`request:${requestId}`);
  }
}

/**
 * Example: Using Stripe's native idempotency support
 */
async function createStripePayment(amount, currency, customer) {
  const idempotencyKey = uuidv4();

  try {
    const paymentIntent = await stripe.paymentIntents.create(
      {
        amount: amount, // Amount in cents
        currency: currency,
        customer: customer,
        confirm: true,
        payment_method: 'pm_card_visa'
      },
      {
        idempotencyKey: idempotencyKey // Stripe automatically handles deduplication
      }
    );

    return paymentIntent;
  } catch (error) {
    // Safe to retry with same idempotency key
    if (error.type === 'StripeConnectionError') {
      console.log('Network error, retrying with same idempotency key...');
      return stripe.paymentIntents.create(
        {
          amount: amount,
          currency: currency,
          customer: customer,
          confirm: true,
          payment_method: 'pm_card_visa'
        },
        {
          idempotencyKey: idempotencyKey // Same key ensures no duplicate charge
        }
      );
    }
    throw error;
  }
}

/**
 * Server-side: Implement Stripe-compatible idempotency endpoint
 */
app.post('/api/v1/payments', idempotencyMiddleware, async (req, res) => {
  const { amount, currency, customerId, paymentMethodId } = req.body;

  // Forward to Stripe with idempotency key from client
  const paymentIntent = await stripe.paymentIntents.create(
    {
      amount,
      currency,
      customer: customerId,
      payment_method: paymentMethodId,
      confirm: true
    },
    {
      idempotencyKey: req.headers['idempotency-key']
    }
  );

  res.status(201).json({
    success: true,
    paymentId: paymentIntent.id,
    status: paymentIntent.status
  });
});

module.exports = { PaymentClient, createStripePayment };

const rateLimit = require('express-rate-limit');
const RedisStore = require('rate-limit-redis');
const redis = require('redis');
const CircuitBreaker = require('opossum');

const redisClient = redis.createClient({
  host: process.env.REDIS_HOST,
  port: 6379
});

// Rate limiting for payment endpoints
const paymentRateLimiter = rateLimit({
  store: new RedisStore({
    client: redisClient,
    prefix: 'rl:payment:'
  }),
  windowMs: 60 * 1000, // 1 minute
  max: 10, // Max 10 payment requests per minute per user
  keyGenerator: (req) => {
    return req.user?.id || req.ip; // Rate limit by user ID or IP
  },
  handler: (req, res) => {
    res.status(429).json({
      error: 'Too many payment requests. Please wait before retrying.',
      code: 'RATE_LIMIT_EXCEEDED',
      retryAfter: res.getHeader('Retry-After')
    });
  },
  skip: (req) => {
    // Skip rate limiting if valid idempotency key provided (safe retry)
    const idempotencyKey = req.headers['idempotency-key'];
    return idempotencyKey && isValidUUID(idempotencyKey);
  }
});

// Stricter rate limiting for failed payment attempts
const failedPaymentLimiter = rateLimit({
  store: new RedisStore({
    client: redisClient,
    prefix: 'rl:failed_payment:'
  }),
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // Max 5 failed attempts per 15 minutes
  keyGenerator: (req) => `${req.user?.id}:failed`,
  skipSuccessfulRequests: true // Only count failures
});

// Circuit breaker for payment gateway calls
const paymentGatewayOptions = {
  timeout: 5000, // 5 second timeout
  errorThresholdPercentage: 50, // Open circuit at 50% error rate
  resetTimeout: 30000, // Try again after 30 seconds
  rollingCountTimeout: 10000, // 10 second rolling window
  rollingCountBuckets: 10,
  volumeThreshold: 10 // Minimum 10 requests before circuit can open
};

async function callPaymentGateway(paymentData) {
  // Simulate payment gateway call
  const response = await fetch('https://payment-gateway.example.com/charge', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(paymentData)
  });

  if (!response.ok) {
    throw new Error(`Gateway error: ${response.status}`);
  }

  return response.json();
}

const paymentBreaker = new CircuitBreaker(callPaymentGateway, paymentGatewayOptions);

// Circuit breaker event handlers
paymentBreaker.on('open', () => {
  console.error('Payment gateway circuit OPEN - failing fast');
  // Alert operations team
});

paymentBreaker.on('halfOpen', () => {
  console.log('Payment gateway circuit HALF-OPEN - testing recovery');
});

paymentBreaker.on('close', () => {
  console.log('Payment gateway circuit CLOSED - normal operation');
});

paymentBreaker.fallback((paymentData) => {
  // Fallback: Queue payment for later processing
  return {
    success: false,
    queued: true,
    message: 'Payment gateway temporarily unavailable. Request queued for processing.',
    retryAfter: 30
  };
});

// Apply middleware to payment endpoint
app.post('/api/v1/payments',
  paymentRateLimiter,
  failedPaymentLimiter,
  idempotencyMiddleware,
  async (req, res) => {
    const { amount, currency, paymentMethodId } = req.body;

    try {
      // Call payment gateway through circuit breaker
      const result = await paymentBreaker.fire({
        userId: req.user.id,
        amount,
        currency,
        paymentMethodId,
        idempotencyKey: req.headers['idempotency-key']
      });

      if (result.queued) {
        return res.status(202).json(result);
      }

      res.status(201).json({
        success: true,
        paymentId: result.id,
        status: result.status
      });
    } catch (error) {
      console.error('Payment failed:', error);

      // Increment failed payment counter
      await redisClient.incr(`failed_payments:${req.user.id}`);

      res.status(500).json({
        error: 'Payment processing failed',
        code: 'PAYMENT_FAILED'
      });
    }
  }
);

function isValidUUID(uuid) {
  const regex = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
  return regex.test(uuid);
}

module.exports = { paymentRateLimiter, paymentBreaker };

